const { parseDuration } = require('./src/core/duration.js');
const cases = [
  ['30s', 30000],
  ['1h30m', 5400000],
  ['500ms', 500],
  ['250', 250],
  ['2h', 7200000],
  ['5m', 300000],
  ['1000ms', 1000],
];
